import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.DisplayName;

class CSVFormatTest {

    @Test
    @DisplayName("isCommentMarkerSet returns false when commentMarker is null")
    void testIsCommentMarkerSetFalse() {
        // Using DEFAULT which has commentMarker null
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.isCommentMarkerSet());
    }

    @Test
    @DisplayName("isCommentMarkerSet returns true when commentMarker is set")
    void testIsCommentMarkerSetTrue() {
        CSVFormat formatWithComment = CSVFormat.DEFAULT.withCommentMarker('#');
        assertTrue(formatWithComment.isCommentMarkerSet());
    }

    @Test
    @DisplayName("isCommentMarkerSet returns true when commentMarker is set as Character object")
    void testIsCommentMarkerSetTrueCharacter() {
        CSVFormat formatWithComment = CSVFormat.DEFAULT.withCommentMarker(Character.valueOf('#'));
        assertTrue(formatWithComment.isCommentMarkerSet());
    }
}
